css:
.loader {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
   width: 28px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: var(--loader-secondary-color, #7dd3fc);
   transform-origin: top;
   display: grid;
   animation: l3-0 1s infinite linear;
}
.loader::before, .loader::after  {
  content: "";
   grid-area: 1/1;
   background:var(--loader-secondary-color, #7dd3fc);
   border-radius: 50%;
   transform-origin: top;
   animation: inherit;
   animation-name: l3-1;
}
.loader::after  {
  background: var(--loader-color, #0284c7);
   --s:180deg;
}
@keyframes l3-0  {
  0%,20% {transform: rotate(0)}
100% {transform: rotate(360deg)}
}
@keyframes l3-1  {
  50% {transform: rotate(var(--s,90deg))}
100% {transform: rotate(0)}
}
